const input = $input.all()[0].json;

return [{
  json: input,
  binary: {
    data: {
      data: Buffer.from(input.html_report, 'utf8'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

const input = $input.all()[0].json;
const { table_data, total_records, columns, generated_at } = input;

// Generate table headers (clean up unwanted columns)
const cleanColumns = columns.filter(col => 
  !col.includes('row_number') && 
  !col.includes('rule_mitre_id') && 
  !col.includes('location') && 
  !col.includes('decoder_name')
);

const tableHeaders = cleanColumns.map(col => {
  let displayName = col.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
  // Simplify some column names
  if (displayName.includes('Data Win')) displayName = displayName.replace('Data Win ', '');
  if (displayName.includes('System ')) displayName = displayName.replace('System ', '');
  if (displayName.includes('Eventdata ')) displayName = displayName.replace('Eventdata ', '');
  return `<th>${displayName}</th>`;
}).join('');

// Generate table rows with cleaned data
const tableRows = table_data.map((row, index) => {
  const cells = cleanColumns.map(col => {
    const value = row[col] || '';
    const displayValue = String(value).length > 500 ? 
      String(value).substring(0, 47) + '...' : String(value);
    return `<td>${displayValue}</td>`;
  }).join('');
  return `<tr>${cells}</tr>`;
}).join('');

// IST timezone dates
const istDate = new Date().toLocaleDateString('en-IN', {
  timeZone: 'Asia/Kolkata',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

const istTime = new Date().toLocaleTimeString('en-IN', {
  timeZone: 'Asia/Kolkata',
  hour12: true,
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
});

const istDateTime = new Date().toLocaleString('en-IN', {
  timeZone: 'Asia/Kolkata',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: true
});

const htmlReport = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Security Event Report</title><style>@page{size:A4 landscape;margin:0.3in}*{margin:0;padding:0;box-sizing:border-box}body{font-family:Arial,sans-serif;font-size:9px;color:#333;background:#fff;padding:10px}.container{max-width:100%;background:white;padding:15px}.header{text-align:center;margin-bottom:15px;border-bottom:2px solid #007bff;padding-bottom:10px}.header h1{color:#007bff;font-size:18px;margin-bottom:5px;font-weight:bold}.header h2{color:#666;font-size:12px;margin-bottom:10px}.header-info{display:flex;justify-content:center;gap:20px;font-size:9px;color:#555;margin-bottom:15px}.info-item{display:flex;flex-direction:column;align-items:center}.info-label{font-weight:bold;color:#007bff;margin-bottom:2px;font-size:8px}.table-container{width:100%}table{width:100%;border-collapse:collapse;font-size:7px;background:white;table-layout:fixed}th{background:#007bff;color:white;padding:3px 2px;text-align:left;font-weight:bold;font-size:7px;white-space:nowrap;border:1px solid #0056b3}td{padding:3px 2px;border:1px solid #ddd;vertical-align:top;word-wrap:break-word;overflow:hidden;text-overflow:ellipsis;font-size:6px}tr:nth-child(even){background:#f8f9fa}.footer{margin-top:10px;text-align:center;border-top:1px solid #ddd;padding-top:8px;font-size:7px;color:#666}</style></head><body><div class="container"><div class="header"><h1>🔐 Wazuh SIEM Security Event Report</h1><h2>Timeline: Last 24 Hours Analysis</h2><div class="header-info"><div class="info-item"><span class="info-label">Report Date</span><span>${istDate}</span></div><div class="info-item"><span class="info-label">Generation Time (IST)</span><span>${istTime}</span></div><div class="info-item"><span class="info-label">Total Records</span><span>${total_records}</span></div></div></div><div class="table-container"><table><thead><tr>${tableHeaders}</tr></thead><tbody>${tableRows}</tbody></table></div><div class="footer"><p><strong>Generated from SIEM System</strong> | Event List ID: 34661620-bac3-11f0-bb75-9b9e70aaad57</p><p>Report generated: ${istDateTime}</p></div></div></body></html>`;

return [{
  json: {
    html_report: htmlReport,
    total_records: total_records,
    report_date: istDate,
    file_name: `security_report_${new Date().toISOString().split('T')[0].replace(/-/g, '')}.html`
  }
}];

// Get the search results from HTTP Request
const searchData = $input.all()[0].json;
const hits = searchData.hits.hits;

// Helper function to safely get nested values
function getValue(obj, path, defaultValue = '') {
  try {
    return path.split('.').reduce((current, key) => {
      return current && current[key] !== undefined ? current[key] : defaultValue;
    }, obj);
  } catch {
    return defaultValue;
  }
}

// Convert each hit to a table row
const tableData = hits.map((hit, index) => {
  const source = hit._source;

  return {
    // Row number
    row_number: index + 1,

    // Timestamp
//timestamp: source.timestamp || '',

    // System info
    system_time: getValue(source, 'data.win.system.systemTime'),
    agent_name: getValue(source, 'agent.name'),
    computer: getValue(source, 'data.win.system.computer'),

    // Network info  
    ip_address: getValue(source, 'data.win.eventdata.ipAddress'),
    ip_port: getValue(source, 'data.win.eventdata.ipPort'),
    workstation_name: getValue(source, 'data.win.eventdata.workstationName'),

    // Event details
    event_id: getValue(source, 'data.win.system.eventID'),
    object_Name: getValue(source, 'data.win.eventdata.objectName'),
    subject_UserName: getValue(source, 'data.win.eventdata.subjectUserName'),
    severity_value: getValue(source, 'data.win.system.severityValue'),

    // Rule info
    rule_id: getValue(source, 'rule.id'),
    rule_level: getValue(source, 'rule.level'),
    rule_description: getValue(source, 'rule.description'),

    // User info
    target_user_name: getValue(source, 'data.win.eventdata.targetUserName'),

    // Additional fields (add more as needed)
    rule_mitre_id: getValue(source, 'rule.mitre.id'),
    rule_mitre_technique: getValue(source, 'rule.mitre.technique'),
    location: getValue(source, 'location'),
    decoder_name: getValue(source, 'decoder.name')
  };
});

// Return the table data with summary info
return {
  table_data: tableData,
  total_records: tableData.length,
  columns: [
    'row_number', 'system_time', 'agent_name', 'computer',
    'ip_address', 'ip_port', 'workstation_name', 'event_id', 'severity_value',
    'rule_id', 'rule_level', 'rule_description', 'target_user_name',
    'object_Name','subject_UserName', 'location', 'decoder_name'
  ],
  generated_at: new Date().toISOString()
};
